import math
import matplotlib.pyplot as plt

class core:
  class point_t:
    def __init__(
        self,
        x: float = 0,
        y: float = 0,
      ):
      self.x = x
      self.y = y

    def __str__(self):
      return f"({self.x}, {self.y})"

    def __add__(self, other):
      return core.point_t(self.x + other.x, self.y + other.y)

    def __truediv__(self, ratio):
      return core.point_t(self.x / ratio, self.y / ratio)

  class line_t:
    def __init__(
        self,
        begin: 'core.point_t',
        end  : 'core.point_t',
      ):
      self.begin = begin
      self.end   = end

    def eq(self
      ):
      denominator = (self.end.x - self.begin.x)
      slope  = ((self.end.y - self.begin.y) / denominator) if denominator else 0
      offset = self.end.y - self.end.x * slope

      return core.line_eq_t(slope, offset)

  class line_eq_t:
    def __init__(
        self,
        slope : float = 0,
        offset: float = 0,
      ):
      self.slope  = slope
      self.offset = offset

    def y(self, x):
      return core.point_t(x, self.slope * x + self.offset)

    def x(self, y):
      return core.point_t((y - self.offset) / self.slope, y)

  class line_fit_t(line_eq_t):
    def __init__(self,
        points: 'list[core.point_t]' = []
      ):
      super(core.line_fit_t, self).__init__()

      self.n = 0
      self.sum_x  = 0.
      self.sum_y  = 0.
      self.sum_xy = 0.
      self.sum_xx = 0.

      for point in points:
        self.add_point(point)

    def add_point(self,
        point: 'core.point_t'
      ):
      self.n += 1
      self.sum_x  += point.x
      self.sum_y  += point.y
      self.sum_xy += point.x * point.y
      self.sum_xx += point.x * point.x

      self.calculate()

    def sub_point(self,
        point: 'core.point_t'
      ):
      self.n -= 1
      self.sum_x  -= point.x
      self.sum_y  -= point.y
      self.sum_xy -= point.x * point.y
      self.sum_xx -= point.x * point.x

      self.calculate()

    def calculate(self
      ):
      denominator = (self.n * self.sum_xx - self.sum_x ** 2)
      self.slope  = ((self.n * self.sum_xy - self.sum_x * self.sum_y) / denominator) if denominator else 0
      self.offset = (self.sum_y - self.slope * self.sum_x) / self.n

  class algebra:
    class distance:
      @staticmethod
      def point_line(
          point: 'core.point_t',
          line : 'core.line_eq_t | core.line_t'
        ):
        if isinstance(line, core.line_t):
          line = line.eq()
        return abs(line.slope * point.x - point.y + line.offset) / math.sqrt(line.slope * line.slope + 1)

      @staticmethod
      def point_point(
          a: 'core.point_t',
          b: 'core.point_t'
        ):
        return math.sqrt((a.x - b.x) ** 2 + (a.y - b.y) ** 2)

    class angle:
      @staticmethod
      def line_line(
          a: 'core.line_eq_t',
          b: 'core.line_eq_t'
        ):
        angle = abs(math.atan(a.slope) - math.atan(b.slope))
        if angle > math.pi / 2:
          angle = math.pi - angle

        return angle

      @staticmethod
      def point_point_point(
          a: 'core.point_t',
          b: 'core.point_t',
          c: 'core.point_t'
        ):
        ba = core.point_t(a.x - b.x, a.y - b.y)
        bc = core.point_t(c.x - b.x, c.y - b.y)

        return math.acos((ba.x * bc.x + ba.y * bc.y) / (math.sqrt(ba.x ** 2 + ba.y ** 2) * (math.sqrt(bc.x ** 2 + bc.y ** 2))))

    class intercept:
      @staticmethod
      def line_line(
          a: 'core.line_eq_t',
          b: 'core.line_eq_t'
        ):
        x = (b.offset - a.offset) / (a.slope - b.slope)
        y = a.slope * x + a.offset

        return core.point_t(x, y)


def simplify_1(
    polygon: '[core.point_t]',
    #
    threshold_curve: float,
    p
  ):
  segments: '[core.line_t]'  = []

  cursor = 0
  while cursor < len(polygon):
    line = core.line_t(polygon[cursor], polygon[cursor + 1])

    cursor += 2
    while cursor < len(polygon):
      if core.algebra.distance.point_line(polygon[cursor], line) >= threshold_curve:
        print(core.algebra.distance.point_line(polygon[cursor], line))
        cursor -= 1
        break
      else:
        line.end = polygon[cursor]

      cursor += 1

    segments.append(line)

  final: '[core.point_t]' = []
  #
  for segment in segments:
    final.append(segment.end)

  xs = list(map(lambda point: point.x, p))
  ys = list(map(lambda point: point.y, p))
  fxs = list(map(lambda point: point.x, final))
  fys = list(map(lambda point: point.y, final))

  plt.plot(xs, ys, color='green', marker='')
  plt.plot(fxs, fys, color='red', marker='o')
  plt.show()

  return final

def simplify_2(
    polygon: '[core.point_t]',
    #
    threshold_curve: float,
    p, d=False
  ):
  xs = list(map(lambda point: point.x, p))
  ys = list(map(lambda point: point.y, p))
  result: '[[core.line_eq_t, core.line_t]]'  = []

  cursor = 0
  while cursor < len(polygon):
    begin = polygon[cursor]
    #
    line = core.line_fit_t()
    line.add_point(polygon[cursor])
    line.add_point(polygon[cursor + 1])

    cursor += 2
    while cursor < len(polygon):
      line.add_point(polygon[cursor])
      if d:
        plt.cla()
        print(core.algebra.distance.point_line(polygon[cursor], line))
        xs = list(map(lambda point: point.x, polygon))
        ys = list(map(lambda point: point.y, polygon))
        plt.plot(xs, ys, color='green', marker='o')
        c = polygon[cursor]
        b = line.y(begin.x)
        e = line.y(c.x)
        print(b, e)
        plt.plot([b.x, e.x], [b.y, e.y], color='red', marker='o')
        plt.plot(c.x, c.y, color='blue', marker='o')
        plt.plot(begin.x, begin.y, color='black', marker='o')
        plt.show()
      if core.algebra.distance.point_line(polygon[cursor], line) >= threshold_curve:
        line.sub_point(polygon[cursor])
        cursor -= 1
        break

      cursor += 1

    end = polygon[cursor if cursor < len(polygon) else 0]

    segment = core.line_t(
      min(line.y(begin.x), line.x(begin.y), key=lambda point: core.algebra.distance.point_point(begin, point)),
      min(line.y(end.x), line.x(end.y), key=lambda point: core.algebra.distance.point_point(end, point))
    )

    result.append([line, segment])

  intercepts = []
  #
  for index in range(len(result)):
    line, segment = result[index]
    #
    last_line, last_segment = result[index - 1]
    next_line, next_segment = result[(index + 1) % len(result)]

    begin = core.algebra.intercept.line_line(last_line, line)
    end   = core.algebra.intercept.line_line(next_line, line)

    intercepts.append(
      core.line_t(
        begin if core.algebra.distance.point_point(begin, segment.begin) < 10 else segment.begin,
        end   if core.algebra.distance.point_point(end  , segment.end)   < 10 else segment.end
      )
    )

  final: '[core.point_t]' = []
  #
  for index in range(len(result)):
    segment = intercepts[index]
    #
    next_segment = intercepts[(index + 1) % len(result)]

    final.append((segment.end + next_segment.begin) / 2)

  xs = list(map(lambda point: point.x, p))
  ys = list(map(lambda point: point.y, p))
  fxs = list(map(lambda point: point.x, final))
  fys = list(map(lambda point: point.y, final))

  plt.plot(xs, ys, color='green', marker='')
  plt.plot(fxs, fys, color='red', marker='o')
  plt.show()

  return final

